from flask.wrappers import Request

# Check class __dict__
for key, value in Request.__dict__.items():
    if '_max' in key:
        print(f"{key}: {value} (type: {type(value)})")

# Check if it's a property on a parent class
for cls in type(Request).__mro__:
    if '_max_form_memory_size' in cls.__dict__:
        print(f"\nFound in {cls}:")
        print(f"  {cls.__dict__['_max_form_memory_size']}")
        print(f"  Type: {type(cls.__dict__['_max_form_memory_size'])}")
