import ast
with open('/workspace/repo/src/flask/wrappers.py', 'r') as f:
    source = f.read()

tree = ast.parse(source)

# Find the Request class
for node in ast.walk(tree):
    if isinstance(node, ast.ClassDef) and node.name == 'Request':
        print('Found Request class')
        for item in node.body:
            if isinstance(item, ast.Assign):
                for target in item.targets:
                    if isinstance(target, ast.Name):
                        print(f'  Assignment: {target.id} = {ast.unparse(item.value)}')
